/**
 * Per-action gas-fee policy. Overrides the global default for a
specific money-movement action (e.g. `withdrawal`, `deposit`,
`wallet_transfer`, `asset_purchase`, `p2p_order`,
`trade_release`).

 */
export interface GasFeeActionPolicy {
  /** Whether the gas-fee gate runs for this action. */
  enabled: boolean;
  /** ETH the user must hold across connected wallets. */
  requiredEthAmount: number;
  /** Default per-transaction ETH fee charged on admin approval
(used as the prefilled value when the admin sets a fee on a
specific withdrawal).
 */
  defaultFeeAmount: number;
  /** How long the user has to fund the gas fee for this action
before the request auto-expires.
 */
  deadlineSeconds: number;
  description: string;
}

/**
 * Action-keyed policy overrides.
 */
export type GasFeeSettingsPerAction = { [key: string]: GasFeeActionPolicy };

/**
 * Platform gas-fee policy. The top-level fields are the global
default; `perAction` overrides individual money-movement actions.

 */
export interface GasFeeSettings {
  /** Default ETH required across all gated actions. */
  requiredEthAmount: number;
  /** Master toggle for the gas-fee gate. */
  enabled: boolean;
  description: string;
  /** Action-keyed policy overrides. */
  perAction?: GasFeeSettingsPerAction;
}

export interface WithdrawalGasFeeStatus {
  enabled: boolean;
  requiredEthAmount: number;
  userEthBalance: number;
  sufficient: boolean;
  message: string;
}

